import React from 'react';
import { motion } from 'framer-motion';

const LoadingSpinner = ({ text = "Cargando..." }) => {
  const containerVariants = {
    start: {
      transition: {
        staggerChildren: 0.1,
      },
    },
    end: {
      transition: {
        staggerChildren: 0.1,
      },
    },
  };

  const circleVariants = {
    start: {
      scale: 1,
      opacity: 0.5,
    },
    end: {
      scale: 1.5,
      opacity: 1,
    },
  };

  const transition = {
    duration: 0.8,
    yoyo: Infinity,
    ease: "easeInOut",
  };

  return (
    <div className="flex flex-col items-center justify-center p-8">
      <motion.div
        className="flex justify-around w-16 h-8"
        variants={containerVariants}
        initial="start"
        animate="end"
      >
        <motion.span
          className="block w-4 h-4 bg-text-muted rounded-full"
          variants={circleVariants}
          transition={transition}
        />
        <motion.span
          className="block w-4 h-4 bg-text-muted rounded-full"
          variants={circleVariants}
          transition={transition}
        />
        <motion.span
          className="block w-4 h-4 bg-text-muted rounded-full"
          variants={circleVariants}
          transition={transition}
        />
      </motion.div>
      <motion.p
        className="mt-4 text-text-muted"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 1, repeat: Infinity, repeatType: "reverse" }}
      >
        {text}
      </motion.p>
    </div>
  );
};

export default LoadingSpinner;
